function sf_theme_clean_palette(array $palette): array { $defaults=sf_theme_default_palette();$clean=[];foreach($defaults as$key=>$default)$clean[$key]=sf_agentic_text($palette[$key]??$default,64,$default);return$clean; }
function sf_theme_create(array $data): int
{
    if(!sf_theme_ready())return 0;$name=sf_agentic_text($data['theme_name']??'New Theme',190,'New Theme');$slug=sf_theme_slug((string)($data['theme_slug']??$name));$palette=json_encode(sf_theme_clean_palette((array)($data['palette']??[])),JSON_UNESCAPED_SLASHES);$status=in_array((string)($data['status']??'draft'),['draft','preview','active','archived'],true)?(string)$data['status']:'draft';
    try{$stmt=sf_theme_db()->prepare('INSERT INTO show_themes (theme_name,theme_slug,description,mood_prompt,palette_json,status) VALUES (?,?,?,?,?,?)');$stmt->execute([$name,$slug,sf_agentic_text($data['description']??'',4000),sf_agentic_text($data['mood_prompt']??'',12000),$palette,$status]);$id=(int)sf_theme_db()->lastInsertId();foreach(sf_theme_default_image_slots()as$slot)sf_theme_upsert_image($id,$slot);return$id;}catch(Throwable$e){error_log('Theme create failed: '.$e->getMessage());return 0;}
}
function sf_theme_update(int $themeId,array $data): bool
{
    if(!sf_theme_ready()||$themeId<=0)return false;$status=in_array((string)($data['status']??'draft'),['draft','preview','active','archived'],true)?(string)$data['status']:'draft';$palette=json_encode(sf_theme_clean_palette((array)($data['palette']??[])),JSON_UNESCAPED_SLASHES);
    try{$stmt=sf_theme_db()->prepare('UPDATE show_themes SET theme_name=?,theme_slug=?,description=?,mood_prompt=?,palette_json=?,status=? WHERE id=?');return$stmt->execute([sf_agentic_text($data['theme_name']??'',190,'Theme'),sf_theme_slug((string)($data['theme_slug']??'')),sf_agentic_text($data['description']??'',4000),sf_agentic_text($data['mood_prompt']??'',12000),$palette,$status,$themeId]);}catch(Throwable$e){return false;}
}
function sf_theme_activate(int $themeId): bool
{
    if(!sf_theme_ready()||$themeId<=0)return false;try{$pdo=sf_theme_db();$pdo->beginTransaction();$pdo->exec('UPDATE show_themes SET is_active=0');$stmt=$pdo->prepare("UPDATE show_themes SET is_active=1,status='active' WHERE id=?");$ok=$stmt->execute([$themeId]);$pdo->commit();return$ok;}catch(Throwable$e){if(sf_theme_db()?->inTransaction())sf_theme_db()->rollBack();return false;}
}
function sf_theme_upsert_image(int $themeId,array $slot): bool
{
    if(!sf_theme_ready()||$themeId<=0)return false;try{$stmt=sf_theme_db()->prepare('INSERT INTO show_theme_images (theme_id,image_key,title,page_location,current_path,aspect_ratio,recommended_size,prompt,status,sort_order) VALUES (?,?,?,?,?,?,?,?,?,?) ON DUPLICATE KEY UPDATE title=VALUES(title),page_location=VALUES(page_location),current_path=VALUES(current_path),aspect_ratio=VALUES(aspect_ratio),recommended_size=VALUES(recommended_size),prompt=VALUES(prompt),status=VALUES(status),sort_order=VALUES(sort_order)');return$stmt->execute([$themeId,sf_theme_slug((string)($slot['image_key']??'image')),sf_agentic_text($slot['title']??'',190,'Image'),sf_agentic_text($slot['page_location']??'',190),sf_agentic_text($slot['current_path']??'',255),sf_agentic_text($slot['aspect_ratio']??'',40),sf_agentic_text($slot['recommended_size']??'',80),sf_agentic_text($slot['prompt']??'',12000),in_array((string)($slot['status']??'active'),['draft','active','generated','approved','archived'],true)?(string)$slot['status']:'draft',max(0,min(9999,(int)($slot['sort_order']??100)))]);}catch(Throwable$e){return false;}
}
function sf_theme_update_image(int $imageId,array $data): bool
{
    if(!sf_theme_ready()||$imageId<=0)return false;$status=in_array((string)($data['status']??'draft'),['draft','active','generated','approved','archived'],true)?(string)$data['status']:'draft';try{$stmt=sf_theme_db()->prepare('UPDATE show_theme_images SET title=?,page_location=?,current_path=?,generated_path=?,approved_path=?,aspect_ratio=?,recommended_size=?,prompt=?,status=?,sort_order=? WHERE id=?');return$stmt->execute([sf_agentic_text($data['title']??'',190,'Image'),sf_agentic_text($data['page_location']??'',190),sf_agentic_text($data['current_path']??'',255),sf_agentic_text($data['generated_path']??'',255),sf_agentic_text($data['approved_path']??'',255),sf_agentic_text($data['aspect_ratio']??'',40),sf_agentic_text($data['recommended_size']??'',80),sf_agentic_text($data['prompt']??'',12000),$status,max(0,min(9999,(int)($data['sort_order']??100))),$imageId]);}catch(Throwable$e){return false;}
