function sf_theme_image_path(array $image,string $field): string { return trim((string)($image[$field]??'')); }
function sf_theme_image_src(array $image,string $field): string { $path=sf_theme_image_path($image,$field);return$path!==''?sf_asset($path):''; }
function sf_theme_image_status_summary(array $image): array { return['current'=>sf_theme_image_path($image,'current_path')!=='','generated'=>sf_theme_image_path($image,'generated_path')!=='','approved'=>sf_theme_image_path($image,'approved_path')!=='','status'=>(string)($image['status']??'draft')]; }
function sf_theme_approve_image(int $imageId): bool { $image=sf_theme_image_find($imageId);if(!$image||sf_theme_image_path($image,'generated_path')==='')return false;try{$stmt=sf_theme_db()->prepare("UPDATE show_theme_images SET approved_path=generated_path,status='approved' WHERE id=?");return$stmt->execute([$imageId]);}catch(Throwable$e){return false;} }
function sf_theme_reject_generated_image(int $imageId): bool { $image=sf_theme_image_find($imageId);if(!$image)return false;try{$status=sf_theme_image_path($image,'approved_path')!==''?'approved':'draft';$stmt=sf_theme_db()->prepare('UPDATE show_theme_images SET generated_path=NULL,status=? WHERE id=?');return$stmt->execute([$status,$imageId]);}catch(Throwable$e){return false;} }
function sf_theme_use_image_as_current(int $imageId,string $source='approved'): bool
{
    if($source!=='approved')return false;$image=sf_theme_image_find($imageId);if(!$image||($image['status']??'')!=='approved')return false;$path=sf_theme_image_path($image,'approved_path');if($path==='')return false;try{$stmt=sf_theme_db()->prepare("UPDATE show_theme_images SET current_path=?,status='active' WHERE id=?");return$stmt->execute([$path,$imageId]);}catch(Throwable$e){return false;}
}
function sf_theme_upload_error_message(int $code): string { $map=[UPLOAD_ERR_INI_SIZE=>'Uploaded file exceeds the server limit.',UPLOAD_ERR_FORM_SIZE=>'Uploaded file exceeds the form limit.',UPLOAD_ERR_PARTIAL=>'File upload was incomplete.',UPLOAD_ERR_NO_FILE=>'No file was selected.',UPLOAD_ERR_NO_TMP_DIR=>'Missing server upload directory.',UPLOAD_ERR_CANT_WRITE=>'Server could not write the uploaded file.',UPLOAD_ERR_EXTENSION=>'A PHP extension blocked the upload.'];return$map[$code]??'Unknown upload error.'; }
function sf_theme_upload_image(int $themeId,int $imageId,array $file): array
{
    $theme=sf_theme_find($themeId);$image=sf_theme_image_find($imageId);if(!$theme||!$image||(int)$image['theme_id']!==$themeId)return['ok'=>false,'message'=>'Theme image slot not found.'];$error=(int)($file['error']??UPLOAD_ERR_NO_FILE);if($error!==UPLOAD_ERR_OK)return['ok'=>false,'message'=>sf_theme_upload_error_message($error)];$tmp=(string)($file['tmp_name']??'');if($tmp===''||!is_uploaded_file($tmp))return['ok'=>false,'message'=>'Upload was not received by the server.'];$bytes=(string)file_get_contents($tmp);$validation=sf_agentic_validate_image_bytes($bytes,12*1024*1024);if(empty($validation['ok']))return['ok'=>false,'message'=>'Only valid JPG, PNG, or WEBP images under 12MB are allowed.'];$extension=['image/png'=>'png','image/jpeg'=>'jpg','image/webp'=>'webp'][$validation['mime']];$themeSlug=sf_theme_slug((string)$theme['theme_slug']);$imageKey=sf_theme_slug((string)$image['image_key']);$dir=dirname(__DIR__).'/assets/images/generated-themes/'.$themeSlug.'/uploads';if(!is_dir($dir)&&!mkdir($dir,0775,true))return['ok'=>false,'message'=>'Could not create theme upload directory.'];$fileName=$imageKey.'-upload-'.date('Ymd-His').'-'.bin2hex(random_bytes(4)).'.'.$extension;$absolute=$dir.'/'.$fileName;if(file_put_contents($absolute,$bytes,LOCK_EX)!==strlen($bytes))return['ok'=>false,'message'=>'Could not save uploaded image.'];@chmod($absolute,0640);$relative='images/generated-themes/'.$themeSlug.'/uploads/'.$fileName;try{$stmt=sf_theme_db()->prepare("UPDATE show_theme_images SET generated_path=?,last_generated_at=NOW(),status='generated' WHERE id=?");$stmt->execute([$relative,$imageId]);sf_theme_create_job($themeId,$imageId,'manual_upload','complete',['original_name'=>basename((string)($file['name']??'')),'mime'=>$validation['mime'],'size'=>strlen($bytes)],$relative,'');return['ok'=>true,'path'=>$relative,'message'=>'Replacement image uploaded into the Generated Preview slot. Approve it before publishing.'];}catch(Throwable$e){@unlink($absolute);return['ok'=>false,'message'=>'Could not register uploaded image.'];}
}
function sf_theme_create_job(int $themeId,?int $imageId,string $action,string $status,array $payload=[],string $path='',string $error=''): int
{
    if(!sf_theme_ready()||!sf_theme_table_exists('show_theme_image_jobs'))return 0;$status=in_array($status,['queued','running','complete','failed','canceled'],true)?$status:'failed';$json=json_encode($payload,JSON_UNESCAPED_SLASHES|JSON_INVALID_UTF8_SUBSTITUTE);if(is_string($json)&&strlen($json)>65535)$json=json_encode(['payload_hash'=>hash('sha256',$json),'truncated'=>true]);try{$stmt=sf_theme_db()->prepare('INSERT INTO show_theme_image_jobs (theme_id,theme_image_id,action_type,status,request_payload,generated_path,error_message,completed_at) VALUES (?,?,?,?,?,?,?,?)');$stmt->execute([$themeId,$imageId,substr($action,0,80),$status,$json,$path!==''?substr($path,0,255):null,$error!==''?substr($error,0,2000):null,in_array($status,['complete','failed','canceled'],true)?date('Y-m-d H:i:s'):null]);return(int)sf_theme_db()->lastInsertId();}catch(Throwable$e){return 0;}
}
function sf_theme_generation_prompt(array $theme,array $image): string
{
    return "<THEME_CONTEXT>\nMood: ".sf_agentic_text($theme['mood_prompt']??'',8000)."\nImage slot: ".sf_agentic_text($image['title']??'',190)."\nLocation: ".sf_agentic_text($image['page_location']??'',190)."\nAspect ratio: ".sf_agentic_text($image['aspect_ratio']??'',40)."\n</THEME_CONTEXT>\n<IMAGE_REQUEST>\n".sf_agentic_text($image['prompt']??'',8000)."\n</IMAGE_REQUEST>\nCreate one production-ready image. No text, UI, logos, signatures, watermarks, or unsafe content.";
}
function sf_theme_generate_image(array $theme,array $image): array
{
    $provider=sf_theme_provider();$themeId=(int)($theme['id']??0);$imageId=(int)($image['id']??0);if(!$themeId||!$imageId)return['ok'=>false,'message'=>'Theme image slot not found.'];$prompt=sf_theme_generation_prompt($theme,$image);$payload=['provider'=>$provider['provider_key']??'chatgpt','model'=>$provider['image_model']??'gpt-image-1','prompt_hash'=>hash('sha256',$prompt),'size'=>'1024x1024'];
    if(!sf_theme_provider_ready($provider)){sf_theme_create_job($themeId,$imageId,'generate_one','failed',$payload,'','Default image provider is not securely configured.');return['ok'=>false,'message'=>'Default image provider is not securely configured in admin/ai-settings.php.'];}
    $key=sf_ai_decrypt_secret($provider['encrypted_api_key']??'');$model=sf_agentic_model_name($provider['image_model']??'')?:'gpt-image-1';$jobId=sf_theme_create_job($themeId,$imageId,'generate_one','running',$payload);
    $result=sf_sbgen_http_json('https://api.openai.com/v1/images/generations',['Content-Type: application/json','Authorization: Bearer '.$key],['model'=>$model,'prompt'=>$prompt,'size'=>'1024x1024','quality'=>'medium','output_format'=>'png','n'=>1],max(30,(int)($provider['timeout_seconds']??120)),max(0,(int)($provider['max_retries']??1)));
    if(!$result['ok']){if($jobId>0)sf_theme_db()->prepare("UPDATE show_theme_image_jobs SET status='failed',error_message=?,completed_at=NOW() WHERE id=?")->execute([substr($result['error'],0,2000),$jobId]);return['ok'=>false,'message'=>'Image API request failed.'];}
    $base64=(string)($result['json']['data'][0]['b64_json']??'');$bytes=base64_decode($base64,true);$validation=$bytes!==false?sf_agentic_validate_image_bytes($bytes):['ok'=>false];if(empty($validation['ok'])){if($jobId>0)sf_theme_db()->prepare("UPDATE show_theme_image_jobs SET status='failed',error_message='Invalid generated image payload.',completed_at=NOW() WHERE id=?")->execute([$jobId]);return['ok'=>false,'message'=>'Generated image payload failed validation.'];}
    $dir=dirname(__DIR__).'/assets/images/generated-themes/'.sf_theme_slug((string)$theme['theme_slug']);if(!is_dir($dir)&&!mkdir($dir,0775,true))return['ok'=>false,'message'=>'Could not create generated theme directory.'];$file=sf_theme_slug((string)$image['image_key']).'-'.date('Ymd-His').'-'.bin2hex(random_bytes(4)).'.png';$absolute=$dir.'/'.$file;if(file_put_contents($absolute,$bytes,LOCK_EX)!==strlen($bytes))return['ok'=>false,'message'=>'Could not save generated image.'];@chmod($absolute,0640);$relative='images/generated-themes/'.sf_theme_slug((string)$theme['theme_slug']).'/'.$file;
    sf_theme_db()->prepare("UPDATE show_theme_images SET generated_path=?,last_generated_at=NOW(),status='generated' WHERE id=?")->execute([$relative,$imageId]);if($jobId>0)sf_theme_db()->prepare("UPDATE show_theme_image_jobs SET status='complete',generated_path=?,completed_at=NOW() WHERE id=?")->execute([$relative,$jobId]);
    $profile=(array)($GLOBALS['sf_agentic_active_profile']??[]);if(($profile['feature']??'')==='theme_image')sf_agentic_finalize_reservation('success',$result['json']['usage']??[]);
    return['ok'=>true,'path'=>$relative,'message'=>'Image generated. Review and approve before publishing.'];
}
function sf_theme_generate_all(int $themeId): array
{
    $theme=sf_theme_find($themeId);if(!$theme)return['ok'=>false,'message'=>'Theme not found.'];$images=sf_theme_images($themeId);$max=max(1,(int)(getenv('SF_AI_MAX_BULK_IMAGES')?:8));if(count($images)>$max)return['ok'=>false,'message'=>'Bulk generation exceeds the configured maximum.'];$results=[];$success=0;foreach($images as$image){$result=sf_theme_generate_image($theme,$image);$results[$image['image_key']]=$result;if(!empty($result['ok']))$success++;else break;}sf_agentic_finalize_reservation($success===count($images)?'success':'failed',[],$success===count($images)?'':'Bulk image generation stopped after a failed item.');return['ok'=>$success===count($images),'results'=>$results,'message'=>$success===count($images)?'All images generated for review.':'Bulk generation stopped safely after a failure.'];
}
